('Intro to Databases', 'intro-to-databases', 'An introduction to the basics of databases.', 'This course covers the fundamental concepts of databases and database management systems.', 'Understand the basics of databases, Learn about relational database models.', 'No specific requirements.', 'English', 49.99, 'Beginner', 'thumbnails/intro_to_databases_thumbnail.jpg', 'https://www.youtube.com/playlist?list=PLQVJk9oC5JKohoyVILfdxOOzyl6w-yOur', True,7, 5, '2023-12-10 20:18:40.994951', '2023-12-10 20:18:40.994963', 4.5),
('Learn Complete SQL', 'learn-complete-sql', 'Master SQL with this comprehensive course.', 'A complete guide to SQL, covering all aspects from basic queries to advanced database operations.', 'Master SQL, Perform complex database queries.', 'Basic understanding of databases.', 'English', 59.99, 'Intermediate', 'thumbnails/learn_complete_sql_thumbnail.jpg', 'https://www.youtube.com/playlist?list=PLavw5C92dz9Ef4E-1Zi9KfCTXS_IN8gXZ', True,7, 5, '2023-12-10 20:18:40.994964', '2023-12-10 20:18:40.994965', 4.8),
('Database Normalization', 'database-normalization', 'Understanding the process of database normalization.', 'Learn the importance of database normalization and how to apply normalization techniques.', 'Understand the normalization process, Apply normalization to database design.', 'Basic knowledge of databases.', 'English', 39.99, 'Intermediate', 'thumbnails/database_normalization_thumbnail.jpg', 'https://www.youtube.com/playlist?list=PLLGlmW7jT-nTr1ory9o2MgsOmmx2w8FB3', True,7, 5, '2023-12-10 20:18:40.994966', '2023-12-10 20:18:40.994966', 4.3),
('NoSQL Databases', 'nosql-databases', 'Exploring the world of NoSQL databases.', 'An in-depth look at different types of NoSQL databases and their use cases.', 'Understand NoSQL database concepts, Choose the right NoSQL database for specific scenarios.', 'Basic understanding of databases.', 'English', 49.99, 'Intermediate', 'thumbnails/nosql_databases_thumbnail.jpg', 'https://www.youtube.com/playlist?list=PLqfPEK2RTgCiDwThc4fm67aXIi3ZzFUgA', True,7, 5, '2023-12-10 20:18:40.994967', '2023-12-10 20:18:40.994967', 4.5),
('Fundamentals of Database Administration', 'fundamentals-of-database-administration', 'Essential skills for effective database administration.', 'Learn the fundamental principles of database administration and management.', 'Acquire database administration skills, Perform routine maintenance tasks.', 'Basic knowledge of databases.', 'English', 54.99, 'Intermediate', 'thumbnails/database_administration_thumbnail.jpg', 'https://www.youtube.com/playlist?list=PLDYqU5RH_aX1hdZ32WfXklJlkh-H74juv', True,7, 5, '2023-12-10 20:18:40.994968', '2023-12-10 20:18:40.994968', 4.7),
('Advanced SQL Concepts', 'advanced-sql-concepts', 'Explore advanced SQL features and techniques.', 'Dive deep into complex SQL concepts and enhance your database querying skills.', 'Master advanced SQL queries, Optimize SQL performance.', 'Strong understanding of SQL fundamentals.', 'English', 64.99, 'Advanced', 'thumbnails/advanced_sql_concepts_thumbnail.jpg', 'https://www.youtube.com/playlist?list=PLbTF1OfX62c3RQ_ZFfyNBWVPdz_OWTMLG', True,7, 5, '2023-12-10 20:18:40.994969', '2023-12-10 20:18:40.994969', 4.9),
('Database Management Systems', 'database-management-systems', 'Comprehensive study of database management systems.', 'Learn about different types of database management systems and their features.', 'Understand DBMS concepts, Choose the right DBMS for specific applications.', 'Basic knowledge of databases.', 'English', 59.99, 'Intermediate', 'thumbnails/dbms_thumbnail.jpg', 'https://www.youtube.com/playlist?list=PLBlnK6fEyqRi_CUQ-FXxgzKQ1dwr_ZJWZ', True,7, 5, '2023-12-10 20:18:40.994970', '2023-12-10 20:18:40.994970', 4.6)


