('The Complete 2023 Web Development Bootcamp', 'complete-2023-web-development-bootcamp', 'A comprehensive web development bootcamp covering the latest technologies.', 'This bootcamp provides hands-on experience in web development with a focus on industry-relevant skills.', 'Build full-stack web applications, Understand web development best practices.', 'Basic understanding of programming concepts.', 'English', 99.99, 'Intermediate', 'thumbnails/the-complete-2023-web-development-bootcamp_thumbnail.jpg', 'https://www.youtube.com/playlist?list=PL8ThWVrtoaIej99JohYT8D6jKWJrNNfBW', True,2, 5, '2023-12-10 21:17:45.650820', '2023-12-10 21:17:45.650828', 4.7),
('JavaScript Tutorials', 'javascript-tutorials', 'Learn JavaScript from the basics to advanced concepts.', 'A series of tutorials that cover JavaScript programming, from the fundamentals to advanced topics.', 'Master JavaScript programming, Build interactive web applications.', 'Basic understanding of HTML and CSS.', 'English', 49.99, 'Beginner', 'thumbnails/javascript-tutorials_thumbnail.jpg', 'https://www.youtube.com/playlist?list=PLTjRvDozrdlxEIuOBZkMAK5uiqp8rHUax', True,2, 5, '2023-12-10 21:17:45.650829', '2023-12-10 21:17:45.650829', 4.5),
('Full Stack Open 2022', 'full-stack-open-2022', 'An in-depth course on full-stack web development using modern technologies.', 'This course covers the entire process of building modern web applications, including front-end and back-end development.', 'Become a full-stack developer, Work with popular web development tools.', 'Intermediate knowledge of JavaScript and web development.', 'English', 79.99, 'Intermediate', 'thumbnails/full-stack-open-2022_thumbnail.jpg', 'https://www.youtube.com/playlist?list=PLAVYuKOCwjTD1bw_xBaiapoIzkqF-e7X4', True,2, 5, '2023-12-10 21:17:45.650830', '2023-12-10 21:17:45.650830', 4.8),
('Web Development Course', 'web-development-course', 'A comprehensive course covering the essentials of web development.', 'Learn the foundational concepts of web development, including HTML, CSS, and JavaScript.', 'Build static and interactive web pages, Understand web design principles.', 'No prerequisites.', 'English', 29.99, 'Beginner', 'thumbnails/web-development-course_thumbnail.jpg', 'https://www.youtube.com/playlist?list=PLfqMhTWNBTe3H6c9OGXb5_6wcc1Mca52n', True,2, 5, '2023-12-10 21:17:45.650831', '2023-12-10 21:17:45.650831', 4.2),
('PHP Course for Beginners', 'php-course-for-beginners', 'Get started with PHP programming for web development.', 'This course is designed for beginners to learn PHP and its applications in web development.', 'Understand PHP basics, Build dynamic web pages with PHP.', 'Basic understanding of HTML and CSS.', 'English', 39.99, 'Beginner', 'thumbnails/php-course-for-beginners_thumbnail.jpg', 'https://www.youtube.com/playlist?list=PL0eyrZgxdwhwwQQZA79OzYwl5ewA7HQih', True,2, 5, '2023-12-10 21:17:45.650832', '2023-12-10 21:17:45.650832', 4.4),
('Full Modern React Tutorial', 'full-modern-react-tutorial', 'Learn React.js with this comprehensive tutorial.', 'A complete guide to React.js, covering modern practices and best development techniques.', 'Master React.js, Build dynamic and responsive user interfaces.', 'Intermediate knowledge of JavaScript and HTML.', 'English', 59.99, 'Intermediate', 'thumbnails/full-modern-react-tutorial_thumbnail.jpg', 'https://www.youtube.com/playlist?list=PL4cUxeGkcC9gZD-Tvwfod2gaISzfRiP9d', True,2, 5, '2023-12-10 21:17:45.650833', '2023-12-10 21:17:45.650833', 4.6)

